INSERT INTO `segment_faqs` (`id`, `segment_id`, `question`, `answer`, `sort_order`) VALUES ('cmrmnuuq9000058vxzb4p3mny','cmr9zg72b00038ckx7by9iu0w','¿Puedo vender por kilo y por pieza en el mismo sistema?','Sí. Cada producto tiene su modo de venta: peso (kg con decimales) o unidad. Los puedes mezclar en el mismo ticket.',1),('cmrmnuuq9000158vxfiv996oh','cmr9zg72b00038ckx7by9iu0w','¿Cómo maneja ActivoPOS la tasa del dólar en la carnicería?','La tasa BCV se actualiza automáticamente. Tú pones el precio en USD y el sistema calcula los bolívares en tiempo real al momento del cobro.',2),('cmrmnuuq9000258vxac4sgwiw','cmr9zg72b00038ckx7by9iu0w','¿Puedo saber cuánto de cada corte me queda?','Sí. El inventario descuenta automáticamente con cada venta. Ves el stock en tiempo real sin tener que contar.',3),('cmrmnuuq9000358vxllcs4w1o','cmr9zg72b00038ckx7by9iu0w','¿ActivoPOS reemplaza mi facturación del SENIAT?','No. ActivoPOS es tu sistema de control de ventas e inventario — no reemplaza tu facturación SENIAT, la complementa. Puedes usar ActivoPOS para el control diario y tu sistema fiscal por separado.',4),('cmrmnuuq9000458vx6yboevk6','cmr9zg72b00038ckx7by9iu0w','¿Necesito instalar algo en mi computadora o teléfono?','No. ActivoPOS corre completamente en el navegador — Chrome, Safari o cualquier browser moderno. Sin instalación, sin actualizaciones manuales. Funciona en teléfono, tablet o computadora.',5),('cmrmnuuq9000558vxg65dl9gf','cmr9zg72b00038ckx7by9iu0w','¿Cómo se actualiza la tasa del dólar?','Automáticamente. ActivoPOS consulta la tasa BCV varias veces al día. Tú defines el precio en USD una sola vez y el sistema calcula los bolívares en tiempo real en cada cobro.',6),('cmrmnuuq9000658vx0j711i24','cmr9zg72b00038ckx7by9iu0w','¿Qué métodos de pago acepta ActivoPOS?','Todos los que usa Venezuela: Pago Móvil, Zelle, efectivo en dólares, efectivo en bolívares, transferencia bancaria y USDT. Un mismo cobro puede mezclar varios métodos.',7),('cmrmnuuq9000758vxmlg1088g','cmr9zg72b00038ckx7by9iu0w','¿Cuánto cuesta ActivoPOS?','El plan Mostrador arranca desde $15/mes. El plan Negocio con catálogo digital es $25/mes. El plan Pro con usuarios ilimitados es $40/mes. Sin contrato anual — pagas mes a mes.',8),('cmrmnuuq9000858vxn28gues1','cmr9zg72b00038ckx7by9iu0w','¿Puedo cancelar cuando quiera?','Sí. No hay contrato anual ni penalización por cancelar. Cancelas cuando quieras y tu cuenta queda activa hasta el final del período pagado.',9),('cmrmnuuq9000958vxeoye6pmp','cmr9zg72b00038ckx7by9iu0w','¿Funciona desde el teléfono?','Sí. ActivoPOS está diseñado mobile-first. El POS, el inventario, los reportes y el catálogo funcionan perfectamente desde cualquier teléfono Android o iPhone.',10),('cmrmnuuq9000a58vx5kppelnz','cmr9zg72b00038ckx7by9iu0w','¿Puedo tener varios usuarios con diferentes permisos?','Sí. Puedes crear usuarios con rol de cajero — solo ven el POS y la caja — o de administrador — acceso completo. Cada uno entra con su propio usuario y contraseña.',11),('cmrmnuuq9000b58vxjd5lyahw','cmr9zg72b00038ckx7by9iu0w','¿Qué pasa si se va la luz o el internet?','Las ventas que ya procesaste quedan guardadas. Para nuevas ventas necesitas conexión — ActivoPOS es 100% en la nube. Recomendamos tener el hotspot del teléfono como respaldo.',12),('cmrmnuur2000c58vxez68623j','cmr9zg74200078ckx54sndlm9','¿ActivoPOS maneja mesas y comandas?','Sí. Puedes tener tickets abiertos por mesa, agregar productos, modificar y cobrar cuando el cliente pida la cuenta.',1),('cmrmnuur2000d58vxvk49qz30','cmr9zg74200078ckx54sndlm9','¿Funciona con pantalla de cocina (KDS)?','Sí, en el plan Pro tienes acceso al módulo KDS — una pantalla donde la cocina ve los pedidos en tiempo real sin papel.',2),('cmrmnuur2000e58vxh6gfsza5','cmr9zg74200078ckx54sndlm9','¿Puedo tener varios cajeros trabajando al mismo tiempo?','Sí. Cada usuario tiene su acceso. Los cajeros ven el POS y los pedidos; el admin ve todo incluyendo reportes y finanzas.',3),('cmrmnuur2000f58vxjsmu88at','cmr9zg74200078ckx54sndlm9','¿ActivoPOS reemplaza mi facturación del SENIAT?','No. ActivoPOS es tu sistema de control de ventas e inventario — no reemplaza tu facturación SENIAT, la complementa. Puedes usar ActivoPOS para el control diario y tu sistema fiscal por separado.',4),('cmrmnuur2000g58vxpgisrd4l','cmr9zg74200078ckx54sndlm9','¿Necesito instalar algo en mi computadora o teléfono?','No. ActivoPOS corre completamente en el navegador — Chrome, Safari o cualquier browser moderno. Sin instalación, sin actualizaciones manuales. Funciona en teléfono, tablet o computadora.',5),('cmrmnuur2000h58vxnx78omxs','cmr9zg74200078ckx54sndlm9','¿Cómo se actualiza la tasa del dólar?','Automáticamente. ActivoPOS consulta la tasa BCV varias veces al día. Tú defines el precio en USD una sola vez y el sistema calcula los bolívares en tiempo real en cada cobro.',6),('cmrmnuur2000i58vx2s47ss3t','cmr9zg74200078ckx54sndlm9','¿Qué métodos de pago acepta ActivoPOS?','Todos los que usa Venezuela: Pago Móvil, Zelle, efectivo en dólares, efectivo en bolívares, transferencia bancaria y USDT. Un mismo cobro puede mezclar varios métodos.',7),('cmrmnuur2000j58vx5i5w2jpo','cmr9zg74200078ckx54sndlm9','¿Cuánto cuesta ActivoPOS?','El plan Mostrador arranca desde $15/mes. El plan Negocio con catálogo digital es $25/mes. El plan Pro con usuarios ilimitados es $40/mes. Sin contrato anual — pagas mes a mes.',8),('cmrmnuur2000k58vx88nhqtn3','cmr9zg74200078ckx54sndlm9','¿Puedo cancelar cuando quiera?','Sí. No hay contrato anual ni penalización por cancelar. Cancelas cuando quieras y tu cuenta queda activa hasta el final del período pagado.',9),('cmrmnuur2000l58vxpfnuylta','cmr9zg74200078ckx54sndlm9','¿Funciona desde el teléfono?','Sí. ActivoPOS está diseñado mobile-first. El POS, el inventario, los reportes y el catálogo funcionan perfectamente desde cualquier teléfono Android o iPhone.',10),('cmrmnuur2000m58vxvfju4bil','cmr9zg74200078ckx54sndlm9','¿Puedo tener varios usuarios con diferentes permisos?','Sí. Puedes crear usuarios con rol de cajero — solo ven el POS y la caja — o de administrador — acceso completo. Cada uno entra con su propio usuario y contraseña.',11),('cmrmnuur2000n58vx8ycovc6o','cmr9zg74200078ckx54sndlm9','¿Qué pasa si se va la luz o el internet?','Las ventas que ya procesaste quedan guardadas. Para nuevas ventas necesitas conexión — ActivoPOS es 100% en la nube. Recomendamos tener el hotspot del teléfono como respaldo.',12),('cmrmnuurx000o58vxiw17rbo0','cmr9zg75i000b8ckxyud1xpu2','¿Puedo buscar productos por código o referencia?','Sí. El POS tiene búsqueda por nombre, SKU y código de barras. También puedes usar la cámara del teléfono como escáner.',1),('cmrmnuurx000p58vxt83zq4d0','cmr9zg75i000b8ckxyud1xpu2','¿ActivoPOS maneja precios al mayor y al detal?','Puedes tener listas de precio por cliente. Un cliente mayorista ve sus precios, uno al detal ve los suyos.',2),('cmrmnuurx000q58vxrxlrg96q','cmr9zg75i000b8ckxyud1xpu2','¿Puedo actualizar precios masivamente cuando sube el dólar?','Sí. Puedes actualizar el costo y el margen de categorías completas. El sistema recalcula los precios automáticamente.',3),('cmrmnuurx000r58vxpymb7uic','cmr9zg75i000b8ckxyud1xpu2','¿ActivoPOS reemplaza mi facturación del SENIAT?','No. ActivoPOS es tu sistema de control de ventas e inventario — no reemplaza tu facturación SENIAT, la complementa. Puedes usar ActivoPOS para el control diario y tu sistema fiscal por separado.',4),('cmrmnuurx000s58vxwx0kum66','cmr9zg75i000b8ckxyud1xpu2','¿Necesito instalar algo en mi computadora o teléfono?','No. ActivoPOS corre completamente en el navegador — Chrome, Safari o cualquier browser moderno. Sin instalación, sin actualizaciones manuales. Funciona en teléfono, tablet o computadora.',5),('cmrmnuurx000t58vxihe9sbi7','cmr9zg75i000b8ckxyud1xpu2','¿Cómo se actualiza la tasa del dólar?','Automáticamente. ActivoPOS consulta la tasa BCV varias veces al día. Tú defines el precio en USD una sola vez y el sistema calcula los bolívares en tiempo real en cada cobro.',6),('cmrmnuurx000u58vxa6kp3tqt','cmr9zg75i000b8ckxyud1xpu2','¿Qué métodos de pago acepta ActivoPOS?','Todos los que usa Venezuela: Pago Móvil, Zelle, efectivo en dólares, efectivo en bolívares, transferencia bancaria y USDT. Un mismo cobro puede mezclar varios métodos.',7),('cmrmnuurx000v58vxe0vcv1o8','cmr9zg75i000b8ckxyud1xpu2','¿Cuánto cuesta ActivoPOS?','El plan Mostrador arranca desde $15/mes. El plan Negocio con catálogo digital es $25/mes. El plan Pro con usuarios ilimitados es $40/mes. Sin contrato anual — pagas mes a mes.',8),('cmrmnuurx000w58vxjqc569uf','cmr9zg75i000b8ckxyud1xpu2','¿Puedo cancelar cuando quiera?','Sí. No hay contrato anual ni penalización por cancelar. Cancelas cuando quieras y tu cuenta queda activa hasta el final del período pagado.',9),('cmrmnuurx000x58vxjzzewcns','cmr9zg75i000b8ckxyud1xpu2','¿Funciona desde el teléfono?','Sí. ActivoPOS está diseñado mobile-first. El POS, el inventario, los reportes y el catálogo funcionan perfectamente desde cualquier teléfono Android o iPhone.',10),('cmrmnuurx000y58vx95oc0s1a','cmr9zg75i000b8ckxyud1xpu2','¿Puedo tener varios usuarios con diferentes permisos?','Sí. Puedes crear usuarios con rol de cajero — solo ven el POS y la caja — o de administrador — acceso completo. Cada uno entra con su propio usuario y contraseña.',11),('cmrmnuurx000z58vxivk5321n','cmr9zg75i000b8ckxyud1xpu2','¿Qué pasa si se va la luz o el internet?','Las ventas que ya procesaste quedan guardadas. Para nuevas ventas necesitas conexión — ActivoPOS es 100% en la nube. Recomendamos tener el hotspot del teléfono como respaldo.',12),('cmrmnuusq001058vxe10ix6kt','cmr9zg76t000f8ckx0f63jm3s','¿ActivoPOS maneja fechas de vencimiento?','Puedes registrar lotes con fecha de vencimiento. El sistema te alerta cuando un producto está próximo a vencer.',1),('cmrmnuusq001158vxawup6aql','cmr9zg76t000f8ckx0f63jm3s','¿Cómo manejo los precios regulados?','Cada producto tiene su precio en USD que tú defines. Si hay precio regulado, lo ingresas manualmente y el sistema lo respeta en el cobro.',2),('cmrmnuusq001258vx7qcm3g89','cmr9zg76t000f8ckx0f63jm3s','¿Puedo vender con Pago Móvil y efectivo en el mismo ticket?','Sí. Un mismo ticket puede tener múltiples métodos de pago: Pago Móvil, Zelle, efectivo USD, efectivo Bs o cualquier combinación.',3),('cmrmnuusq001358vxr2eq1550','cmr9zg76t000f8ckx0f63jm3s','¿ActivoPOS reemplaza mi facturación del SENIAT?','No. ActivoPOS es tu sistema de control de ventas e inventario — no reemplaza tu facturación SENIAT, la complementa. Puedes usar ActivoPOS para el control diario y tu sistema fiscal por separado.',4),('cmrmnuusq001458vxk3eek1e4','cmr9zg76t000f8ckx0f63jm3s','¿Necesito instalar algo en mi computadora o teléfono?','No. ActivoPOS corre completamente en el navegador — Chrome, Safari o cualquier browser moderno. Sin instalación, sin actualizaciones manuales. Funciona en teléfono, tablet o computadora.',5),('cmrmnuusq001558vxdtasvn56','cmr9zg76t000f8ckx0f63jm3s','¿Cómo se actualiza la tasa del dólar?','Automáticamente. ActivoPOS consulta la tasa BCV varias veces al día. Tú defines el precio en USD una sola vez y el sistema calcula los bolívares en tiempo real en cada cobro.',6),('cmrmnuusq001658vxdfjrvi2e','cmr9zg76t000f8ckx0f63jm3s','¿Qué métodos de pago acepta ActivoPOS?','Todos los que usa Venezuela: Pago Móvil, Zelle, efectivo en dólares, efectivo en bolívares, transferencia bancaria y USDT. Un mismo cobro puede mezclar varios métodos.',7),('cmrmnuusq001758vx74adupx7','cmr9zg76t000f8ckx0f63jm3s','¿Cuánto cuesta ActivoPOS?','El plan Mostrador arranca desde $15/mes. El plan Negocio con catálogo digital es $25/mes. El plan Pro con usuarios ilimitados es $40/mes. Sin contrato anual — pagas mes a mes.',8),('cmrmnuusq001858vxfr0hted5','cmr9zg76t000f8ckx0f63jm3s','¿Puedo cancelar cuando quiera?','Sí. No hay contrato anual ni penalización por cancelar. Cancelas cuando quieras y tu cuenta queda activa hasta el final del período pagado.',9),('cmrmnuusq001958vxwdr1cxe4','cmr9zg76t000f8ckx0f63jm3s','¿Funciona desde el teléfono?','Sí. ActivoPOS está diseñado mobile-first. El POS, el inventario, los reportes y el catálogo funcionan perfectamente desde cualquier teléfono Android o iPhone.',10),('cmrmnuusq001a58vxzz81qnbx','cmr9zg76t000f8ckx0f63jm3s','¿Puedo tener varios usuarios con diferentes permisos?','Sí. Puedes crear usuarios con rol de cajero — solo ven el POS y la caja — o de administrador — acceso completo. Cada uno entra con su propio usuario y contraseña.',11),('cmrmnuusq001b58vxtscn61ko','cmr9zg76t000f8ckx0f63jm3s','¿Qué pasa si se va la luz o el internet?','Las ventas que ya procesaste quedan guardadas. Para nuevas ventas necesitas conexión — ActivoPOS es 100% en la nube. Recomendamos tener el hotspot del teléfono como respaldo.',12),('cmrmnuutc001c58vxm1iiglcs','cmr9zg77o000j8ckxnupx6s25','¿Puedo manejar tallas y colores como variantes?','Sí. Cada producto puede tener variantes (talla S, M, L / color rojo, azul). El inventario lleva el stock de cada combinación por separado.',1),('cmrmnuutc001d58vxohb8qixe','cmr9zg77o000j8ckxnupx6s25','¿Puedo publicar mi catálogo para que clientes vean qué hay?','Sí. ActivoPOS te da un catálogo digital en tutienda.activopos.com. Los clientes ven los productos disponibles y pueden pedir por WhatsApp.',2),('cmrmnuutc001e58vxxz802dfw','cmr9zg77o000j8ckxnupx6s25','¿Maneja ventas a crédito o apartados?','Sí. Puedes registrar ventas a crédito, llevar el saldo del cliente y registrar abonos parciales. Todo queda en el historial.',3),('cmrmnuutc001f58vx78su67yx','cmr9zg77o000j8ckxnupx6s25','¿ActivoPOS reemplaza mi facturación del SENIAT?','No. ActivoPOS es tu sistema de control de ventas e inventario — no reemplaza tu facturación SENIAT, la complementa. Puedes usar ActivoPOS para el control diario y tu sistema fiscal por separado.',4),('cmrmnuutc001g58vxc3fq74qf','cmr9zg77o000j8ckxnupx6s25','¿Necesito instalar algo en mi computadora o teléfono?','No. ActivoPOS corre completamente en el navegador — Chrome, Safari o cualquier browser moderno. Sin instalación, sin actualizaciones manuales. Funciona en teléfono, tablet o computadora.',5),('cmrmnuutc001h58vxv1u8rbn8','cmr9zg77o000j8ckxnupx6s25','¿Cómo se actualiza la tasa del dólar?','Automáticamente. ActivoPOS consulta la tasa BCV varias veces al día. Tú defines el precio en USD una sola vez y el sistema calcula los bolívares en tiempo real en cada cobro.',6),('cmrmnuutc001i58vx8linn1uq','cmr9zg77o000j8ckxnupx6s25','¿Qué métodos de pago acepta ActivoPOS?','Todos los que usa Venezuela: Pago Móvil, Zelle, efectivo en dólares, efectivo en bolívares, transferencia bancaria y USDT. Un mismo cobro puede mezclar varios métodos.',7),('cmrmnuutc001j58vx3nq32sej','cmr9zg77o000j8ckxnupx6s25','¿Cuánto cuesta ActivoPOS?','El plan Mostrador arranca desde $15/mes. El plan Negocio con catálogo digital es $25/mes. El plan Pro con usuarios ilimitados es $40/mes. Sin contrato anual — pagas mes a mes.',8),('cmrmnuutc001k58vxkot3b54t','cmr9zg77o000j8ckxnupx6s25','¿Puedo cancelar cuando quiera?','Sí. No hay contrato anual ni penalización por cancelar. Cancelas cuando quieras y tu cuenta queda activa hasta el final del período pagado.',9),('cmrmnuutc001l58vxfaxuuex9','cmr9zg77o000j8ckxnupx6s25','¿Funciona desde el teléfono?','Sí. ActivoPOS está diseñado mobile-first. El POS, el inventario, los reportes y el catálogo funcionan perfectamente desde cualquier teléfono Android o iPhone.',10),('cmrmnuutc001m58vxs1w4ozhn','cmr9zg77o000j8ckxnupx6s25','¿Puedo tener varios usuarios con diferentes permisos?','Sí. Puedes crear usuarios con rol de cajero — solo ven el POS y la caja — o de administrador — acceso completo. Cada uno entra con su propio usuario y contraseña.',11),('cmrmnuutc001n58vxfpdgq3z6','cmr9zg77o000j8ckxnupx6s25','¿Qué pasa si se va la luz o el internet?','Las ventas que ya procesaste quedan guardadas. Para nuevas ventas necesitas conexión — ActivoPOS es 100% en la nube. Recomendamos tener el hotspot del teléfono como respaldo.',12),('cmrmnuuu6001o58vxvq2tm6qb','cmr9zg78b000n8ckx58cmemx4','¿ActivoPOS funciona para bodegas con muchos productos?','Sí. No hay límite de productos en los planes Negocio y Pro. Puedes tener cientos de referencias con su stock individual.',1),('cmrmnuuu6001p58vx30rd8civ','cmr9zg78b000n8ckx58cmemx4','¿Cómo manejo los fiaditos o ventas a crédito?','Registras al cliente y sus ventas a crédito quedan en su cuenta. Ves cuánto te debe y registras los pagos cuando lleguen.',2),('cmrmnuuu6001q58vxz27r24q7','cmr9zg78b000n8ckx58cmemx4','¿Funciona con caja registradora o lector de código de barras?','ActivoPOS funciona en cualquier dispositivo con navegador — tablet, teléfono, computador. Puedes usar la cámara como escáner de código de barras.',3),('cmrmnuuu6001r58vxtbxhzru3','cmr9zg78b000n8ckx58cmemx4','¿ActivoPOS reemplaza mi facturación del SENIAT?','No. ActivoPOS es tu sistema de control de ventas e inventario — no reemplaza tu facturación SENIAT, la complementa. Puedes usar ActivoPOS para el control diario y tu sistema fiscal por separado.',4),('cmrmnuuu6001s58vx8nkqf1zo','cmr9zg78b000n8ckx58cmemx4','¿Necesito instalar algo en mi computadora o teléfono?','No. ActivoPOS corre completamente en el navegador — Chrome, Safari o cualquier browser moderno. Sin instalación, sin actualizaciones manuales. Funciona en teléfono, tablet o computadora.',5),('cmrmnuuu6001t58vxtah3wt3g','cmr9zg78b000n8ckx58cmemx4','¿Cómo se actualiza la tasa del dólar?','Automáticamente. ActivoPOS consulta la tasa BCV varias veces al día. Tú defines el precio en USD una sola vez y el sistema calcula los bolívares en tiempo real en cada cobro.',6),('cmrmnuuu6001u58vx7ouhgqel','cmr9zg78b000n8ckx58cmemx4','¿Qué métodos de pago acepta ActivoPOS?','Todos los que usa Venezuela: Pago Móvil, Zelle, efectivo en dólares, efectivo en bolívares, transferencia bancaria y USDT. Un mismo cobro puede mezclar varios métodos.',7),('cmrmnuuu6001v58vxia0avitd','cmr9zg78b000n8ckx58cmemx4','¿Cuánto cuesta ActivoPOS?','El plan Mostrador arranca desde $15/mes. El plan Negocio con catálogo digital es $25/mes. El plan Pro con usuarios ilimitados es $40/mes. Sin contrato anual — pagas mes a mes.',8),('cmrmnuuu6001w58vxhys169d7','cmr9zg78b000n8ckx58cmemx4','¿Puedo cancelar cuando quiera?','Sí. No hay contrato anual ni penalización por cancelar. Cancelas cuando quieras y tu cuenta queda activa hasta el final del período pagado.',9),('cmrmnuuu6001x58vxo2v3fajv','cmr9zg78b000n8ckx58cmemx4','¿Funciona desde el teléfono?','Sí. ActivoPOS está diseñado mobile-first. El POS, el inventario, los reportes y el catálogo funcionan perfectamente desde cualquier teléfono Android o iPhone.',10),('cmrmnuuu6001y58vx31tzx9mr','cmr9zg78b000n8ckx58cmemx4','¿Puedo tener varios usuarios con diferentes permisos?','Sí. Puedes crear usuarios con rol de cajero — solo ven el POS y la caja — o de administrador — acceso completo. Cada uno entra con su propio usuario y contraseña.',11),('cmrmnuuu6001z58vxo7h3jned','cmr9zg78b000n8ckx58cmemx4','¿Qué pasa si se va la luz o el internet?','Las ventas que ya procesaste quedan guardadas. Para nuevas ventas necesitas conexión — ActivoPOS es 100% en la nube. Recomendamos tener el hotspot del teléfono como respaldo.',12),('cmrmnuuut002058vxaycj42bv','cmr9zg797000r8ckxkrm2k26b','¿Puedo registrar el serial de cada equipo vendido?','Sí. Puedes agregar notas y especificaciones a cada producto vendido. El historial del cliente guarda todos sus equipos.',1),('cmrmnuuut002158vxw58redxy','cmr9zg797000r8ckxkrm2k26b','¿ActivoPOS maneja órdenes de servicio técnico?','Sí, con el módulo de cotizaciones y servicios. Creas la orden, le das seguimiento y cobras al cerrar.',2),('cmrmnuuut002258vxag75ucms','cmr9zg797000r8ckxkrm2k26b','¿Cómo mantengo los precios actualizados en dólares?','Defines el precio en USD. La tasa BCV se actualiza automáticamente. Nunca más calcular bolívares a mano.',3),('cmrmnuuut002358vx92l1h6zp','cmr9zg797000r8ckxkrm2k26b','¿ActivoPOS reemplaza mi facturación del